nt-bold"><input type="hidden" :name="`values[${index}][is_active]`" value="0"><input type="checkbox" :name="`values[${index}][is_active]`" value="1" x-model="value.is_active"> Active</label><button type="button" class="btn btn-white text-red-700" x-on:click="values.splice(index,1)">Remove</button></div></div></template><button type="button" class="btn btn-white" x-on:click="addValue()">+ Add Value</button></div></x-admin.section-card>
