@once<script>function attributeForm(initial){return{values:(initial||[]).map((v,i)=>({...v,key:v.existing_id||`old-${i}`})),addValue(){this.values.push({key:`new-${Date.now()}-${Math.random()}`,existing_id:'',label:'',slug:'',color_hex:'',image_url:'',image_preview:'',numeric_value:'',is_active:true,sort_order:this.values.length})},autoSlug(v){if(v.existing_id||v.slug)return;v.slug=(v.label||'').toLowerCase().trim().replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'')}}}</script>@endonce
